exercises.starter:
function countRenderPhases(updates) {
  // Each update: { id, prevType, nextType }
  // Return { remounts: number, updates: number }
}

exercises.tests:
check('empty array', () => {
  const r = countRenderPhases([]);
  expect(r.remounts).toBe(0);
  expect(r.updates).toBe(0);
});
check('all same type', () => {
  const r = countRenderPhases([{id:1,prevType:'div',nextType:'div'},{id:2,prevType:'span',nextType:'span'}]);
  expect(r.remounts).toBe(0);
  expect(r.updates).toBe(2);
});
check('mixed', () => {
  const r = countRenderPhases([{id:1,prevType:'div',nextType:'span'},{id:2,prevType:'p',nextType:'p'}]);
  expect(r.remounts).toBe(1);
  expect(r.updates).toBe(1);
});

exercises.solution:
function countRenderPhases(updates) {
  let remounts = 0, updates = 0;
  for (const u of updates) {
    if (u.prevType !== u.nextType) remounts++;
    else updates++;
  }
  return { remounts, updates };
}

