exercises.solution:
function buildDepsChangedMask(prevDeps, nextDeps) {
  if (!prevDeps || !nextDeps) return [];
  return prevDeps.map((v, i) => !Object.is(v, nextDeps[i]));
}

exercises.starter:
function shallowEqual(a, b) {
  // Return true if a and b are shallowly equal
}

exercises.tests:
check('same primitive', () => expect(shallowEqual(1, 1)).toBe(true));
check('different primitives', () => expect(shallowEqual(1, 2)).toBe(false));
check('same object values', () => expect(shallowEqual({x:1,y:2},{x:1,y:2})).toBe(true));
check('different object values', () => expect(shallowEqual({x:1},{x:2})).toBe(false));
check('different key count', () => expect(shallowEqual({x:1},{x:1,y:2})).toBe(false));
check('nested object always false', () => expect(shallowEqual({a:{b:1}},{a:{b:1}})).toBe(false));

exercises.solution:
function shallowEqual(a, b) {
  if (a === b) return true;
  if (typeof a !== 'object' || typeof b !== 'object') return false;
  if (a === null || b === null) return false;
  const keysA = Object.keys(a);
  const keysB = Object.keys(b);
  if (keysA.length !== keysB.length) return false;
  return keysA.every(k => a[k] === b[k]);
}

exercises.starter:
function diffLists(prevKeys, nextKeys) {
  // prevKeys and nextKeys are arrays of string keys
  // Return { added: string[], removed: string[], moved: boolean }
}

exercises.tests:
check('no change', () => {
  const r = diffLists(['a','b','c'], ['a','b','c']);
  expect(r.added).toEqual([]);
  expect(r.removed).toEqual([]);
  expect(r.moved).toBe(false);
});
check('added item', () => {
  const r = diffLists(['a','b'], ['a','b','c']);
  expect(r.added).toEqual(['c']);
  expect(r.removed).toEqual([]);
});
check('removed item', () => {
  const r = diffLists(['a','b','c'], ['a','c']);
  expect(r.removed).toEqual(['b']);
});
check('reorder detected', () => {
  const r = diffLists(['a','b','c'], ['c','a','b']);
  expect(r.moved).toBe(true);
});

exercises.solution:
function diffLists(prevKeys, nextKeys) {
  const prevSet = new Set(prevKeys);
  const nextSet = new Set(nextKeys);
  const added = nextKeys.filter(k => !prevSet.has(k));
  const removed = prevKeys.filter(k => !nextSet.has(k));
  const common = prevKeys.filter(k => nextSet.has(k));
  const commonNext = nextKeys.filter(k => prevSet.has(k));
  let moved = false;
  for (let i = 0; i < common.length; i++) {
    if (common[i] !== commonNext[i]) { moved = true; break; }
  }
  return { added, removed, moved };
}

