function createReducer(initialState, handlers) {
  // Return a reducer function (state, action) => state
}

exercises.tests:
const reducer = createReducer({ count: 0 }, {
  increment: (state, action) => ({ ...state, count: state.count + (action.payload || 1) }),
  reset: () => ({ count: 0 })
});
check('initial state', () => expect(reducer(undefined, { type: '@@INIT' })).toEqual({ count: 0 }));
check('increment', () => expect(reducer({ count: 5 }, { type: 'increment', payload: 3 })).toEqual({ count: 8 }));
check('reset', () => expect(reducer({ count: 99 }, { type: 'reset' })).toEqual({ count: 0 }));
