  const s = { count: 7 };
  expect(reducer(s, { type: 'unknown' })).toEqual(s);
});

exercises.solution:
function createReducer(initialState, handlers) {
  return function reducer(state = initialState, action) {
    const handler = handlers[action.type];
    return handler ? handler(state, action) : state;
  };
}

exercises.starter:
function createStore(initializer) {
  // Return { getState, setState, subscribe }
}

exercises.tests:
const store = createStore((set, get) => ({
  count: 0,
  inc: () => set({ count: get().count + 1 })
}));
check('initial state', () => expect(store.getState().count).toBe(0));
check('setState merges', () => {
  store.setState({ count: 5 });
  expect(store.getState().count).toBe(5);
});
check('action via get', () => {
  store.setState({ count: 0 });
  store.getState().inc();
  expect(store.getState().count).toBe(1);
});
check('subscribe notified', () => {
  let called = 0;
  const unsub = store.subscribe(() => called++);
  store.setState({ count: 99 });
  unsub();
  store.setState({ count: 100 });
  expect(called).toBe(1);
});

exercises.solution:
function createStore(initializer) {
  let state;
  const listeners = new Set();
  const getState = () => state;
  const setState = (partial) => {
    state = { ...state, ...(typeof partial === 'function' ? partial(state) : partial) };
    listeners.forEach(l => l(state));
  };
  const subscribe = (listener) => {
    listeners.add(listener);
    return () => listeners.delete(listener);
  };
  state = initializer(setState, getState);
  return { getState, setState, subscribe };
}

exercises.starter:
function createSimpleCache(ttlMs) {
  // Return { get(key), set(key, value) }
}

exercises.tests:
const cache = createSimpleCache(100);
check('miss on empty', () => expect(cache.get('x')).toBe(undefined));
check('hit after set', () => {
  cache.set('a', 42);
  expect(cache.get('a')).toBe(42);
});
check('expired entry', () => {
  const c2 = createSimpleCache(0);
  c2.set('b', 7);
  expect(c2.get('b')).toBe(undefined);
});
check('overwrite resets ttl', () => {
  const c3 = createSimpleCache(100);
  c3.set('k', 1);
  c3.set('k', 2);
  expect(c3.get('k')).toBe(2);
});

exercises.solution:
function createSimpleCache(ttlMs) {
  const store = new Map();
  return {
    get(key) {
      const entry = store.get(key);
      if (!entry) return undefined;
      if (Date.now() - entry.ts > ttlMs) { store.delete(key); return undefined; }
      return entry.value;
    },
    set(key, value) {
      store.set(key, { value, ts: Date.now() });
    }
  };
}

exercises.starter:
function getVisibleRange(scrollTop, viewportHeight, itemHeight, totalItems) {
  // Return { start, end } with 2-item overscan, clamped to valid range
}

exercises.tests:
check('basic visible range', () => {
  const r = getVisibleRange(0, 500, 50, 1000);
  expect(r.start).toBe(0);
  expect(r.end).toBe(11);
});
check('mid-scroll', () => {
  const r = getVisibleRange(500, 500, 50, 1000);
  expect(r.start).toBe(8);
  expect(r.end).toBe(21);
});
check('clamped at end', () => {
  const r = getVisibleRange(49500, 500, 50, 1000);
  expect(r.end).toBe(999);
});
check('clamped at start', () => {
  const r = getVisibleRange(0, 100, 50, 100);
  expect(r.start).toBe(0);
});

exercises.solution:
function getVisibleRange(scrollTop, viewportHeight, itemHeight, totalItems) {
  const overscan = 2;
  const firstVisible = Math.floor(scrollTop / itemHeight);
  const lastVisible = Math.floor((scrollTop + viewportHeight - 1) / itemHeight);
  const start = Math.max(0, firstVisible - overscan);
  const end = Math.min(totalItems - 1, lastVisible + overscan);
  return { start, end };
}

exercises.starter:
function scheduleAnimationFrames(tasks, runFrame) {
  // Schedule each task in a separate runFrame call
  // Return { cancel() } to stop remaining tasks
}

exercises.tests:
const log = [];
const frames = [];
const runFrame = (cb) => frames.push(cb);
const { cancel } = scheduleAnimationFrames(
  [() => log.push('a'), () => log.push('b'), () => log.push('c')],
  runFrame
);
check('no tasks run before frames fire', () => expect(log).toEqual([]));
frames[0]();
check('first frame runs first task', () => expect(log).toEqual(['a']));
frames[1]();
check('second frame runs second task', () => expect(log).toEqual(['a','b']));
cancel();
if (frames[2]) frames[2]();
check('cancel prevents remaining tasks', () => expect(log).toEqual(['a','b']));

exercises.solution:
function scheduleAnimationFrames(tasks, runFrame) {
  let cancelled = false;
  let i = 0;
  function scheduleNext() {
    if (cancelled || i >= tasks.length) return;
    const task = tasks[i++];
    runFrame(() => {
      if (!cancelled) { task(); scheduleNext(); }
    });
  }
  scheduleNext();
  return { cancel() { cancelled = true; } };
}

exercises.starter:
function simulatePropagation(path, listeners, eventPhase) {
  // Simulate capture or bubble phase, calling appropriate listener fns
  // Return array of [elementName, phaseName] in call order
}

exercises.tests:
const called = [];
const ls = {
  doc: { capture: (el) => called.push([el,'capture']), bubble: (el) => called.push([el,'bubble']) },
  div: { bubble: (el) => called.push([el,'bubble']) },
  btn: { capture: (el) => called.push([el,'capture']), bubble: (el) => called.push([el,'bubble']) }
};
called.length = 0;
simulateP = (path, ls, phase) => simulatePropagation(path, ls, phase);
const capResult = simulatePropagation(['doc','div','btn'], ls, 'capture');
check('capture fires outer to inner', () => {
  const names = capResult.map(x => x[0]);
  expect(names).toEqual(['doc','btn']);
});
const bubResult = simulatePropagation(['doc','div','btn'], ls, 'bubble');
check('bubble fires inner to outer', () => {
  const names = bubResult.map(x => x[0]);
  expect(names).toEqual(['btn','div','doc']);
});

exercises.solution:
function simulatePropagation(path, listeners, eventPhase) {
  const result = [];
  const order = eventPhase === 'capture' ? path : [...path].reverse();
  for (const el of order) {
    const handler = listeners[el]?.[eventPhase];
    if (handler) { handler(el); result.push([el, eventPhase]); }
  }
  return result;
}

exercises.tests:
const trap = buildFocusTrap(['close', 'input', 'cancel', 'confirm']);
check('next from first', () => expect(trap.next('close')).toBe('input'));
check('next wraps', () => expect(trap.next('confirm')).toBe('close'));
check('prev from last', () => expect(trap.prev('confirm')).toBe('cancel'));
check('prev wraps', () => expect(trap.prev('close')).toBe('confirm'));
check('single element', () => {
  const t = buildFocusTrap(['x']);
  expect(t.next('x')).toBe('x');
  expect(t.prev('x')).toBe('x');
});

exercises.solution:
function buildFocusTrap(elements) {
  return {
    next(current) {
      const i = elements.indexOf(current);
      return elements[(i + 1) % elements.length];
    },
    prev(current) {
      const i = elements.indexOf(current);
      return elements[(i - 1 + elements.length) % elements.length];
    }
  };
}
